import React, { useState, useEffect } from "react";
import axios from "axios";
import api from "../../api";

const API_URL = process.env.REACT_APP_API_URL || "http://localhost:5000";

const SendEmailPage = () => {
  const [subject, setSubject] = useState("");
  const [group, setGroup] = useState("all");
  const [template, setTemplate] = useState("promotion");
  const [html, setHtml] = useState("");
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState(null);
  const [error, setError] = useState(null);

  // ===============================
  // 🎨 TEMPLATE MẪU EMAIL
  // ===============================
  const templates = {
    promotion: `
      <h1>🎉 Ưu đãi đặc biệt</h1>
      <p>Giảm giá 20% tất cả sản phẩm trong tuần này!</p>
    `,
    newProducts: `
      <h1>🌸 Sản phẩm mới</h1>
      <p>Khám phá bộ sưu tập hoa mới nhất của chúng tôi!</p>
    `,
    thankyou: `
      <h1>💖 Cảm ơn bạn!</h1>
      <p>Cảm ơn bạn đã đồng hành cùng DTP Flower Shop.</p>
    `
  };

  // Tự load preview khi đổi template
  useEffect(() => {
    setHtml(templates[template]);
  }, [template]);

  // ===============================
  // 📩 GỬI EMAIL
  // ===============================
  const sendEmail = async () => {
    if (!subject || !html) {
      setError("Vui lòng nhập tiêu đề và nội dung email.");
      return;
    }

    setLoading(true);
    setError(null);
    setMessage(null);

    try {
      const res = await axios.post(`${API_URL}/api/email/send`, {
        subject,
        group,
        html,
        templateName: template
      });

      if (res.data.success) {
        setMessage(res.data.message);
      } else {
        setError(res.data.message || "Gửi email thất bại");
      }
    } catch (err) {
      console.log(err);
      setError("Gửi email thất bại!");
    }

    setLoading(false);
  };

  return (
    <div className="email-container">
      <h1 className="title">📩 Gửi Email Marketing</h1>

      <div className="card">
        {/* Tiêu đề */}
        <label>Tiêu đề Email</label>
        <input
          type="text"
          placeholder="Nhập tiêu đề..."
          value={subject}
          onChange={(e) => setSubject(e.target.value)}
        />

        {/* Gửi đến nhóm */}
        <label>Gửi đến nhóm</label>
        <select value={group} onChange={(e) => setGroup(e.target.value)}>
          <option value="all">📢 Tất cả</option>
          <option value="user">👤 Người dùng</option>
          <option value="admin">🛠 Admin</option>
          <option value="newsletter">📬 Newsletter</option>
          <option value="vip">💎 VIP</option>
        </select>

        {/* Mẫu email */}
        <label>Mẫu email</label>
        <select value={template} onChange={(e) => setTemplate(e.target.value)}>
          <option value="promotion">🎁 Khuyến mãi</option>
          <option value="newProducts">🌼 Sản phẩm mới</option>
          <option value="thankyou">🙏 Cảm ơn</option>
        </select>

        <button className="btn-send" onClick={sendEmail} disabled={loading}>
          {loading ? "Đang gửi..." : "📨 Gửi Email"}
        </button>

        {/* Thông báo */}
        {error && <div className="alert error">❌ {error}</div>}
        {message && <div className="alert success">✅ {message}</div>}
      </div>

      {/* Preview email */}
      <div className="preview-box">
        <h2>✨ Preview email</h2>
        <div
          className="preview-content"
          dangerouslySetInnerHTML={{ __html: html }}
        />
      </div>
    </div>
  );
};

export default SendEmailPage;
